export type OpenRouterReasoningEffort = "xhigh" | "high" | "medium" | "low" | "minimal" | "none";

export type OpenRouterReasoningOptions = {
  enabled?: boolean;
  exclude?: boolean;
  max_tokens?: number;
  effort?: OpenRouterReasoningEffort;
};

export type InferenceProvider = "openrouter" | "ollama";

export type ServerConfig = {
  inferenceProvider: InferenceProvider;
  openRouterApiKey?: string;
  ollamaBaseUrl?: string;
  chatAgentModelId: string;
  extractionModelId: string;
  pmAgentModelId: string;
  analyticsAgentModelId: string;
  embeddingModelId: string;
  embeddingDimension: number;
  extractionStoreThreshold: number;
  extractionDisplayThreshold: number;
  openRouterReasoning?: OpenRouterReasoningOptions;
  surrealUrl: string;
  surrealUsername: string;
  surrealPassword: string;
  surrealNamespace: string;
  surrealDatabase: string;
  port: number;
  observerModelId: string;
  scorerModelId: string;
  githubWebhookSecret?: string;
  betterAuthSecret: string;
  betterAuthUrl: string;
  githubClientId: string;
  githubClientSecret: string;
};

export function loadServerConfig(): ServerConfig {
  const inferenceProvider = parseInferenceProvider();

  const openRouterApiKey = inferenceProvider === "openrouter"
    ? requireEnv("OPENROUTER_API_KEY")
    : Bun.env.OPENROUTER_API_KEY?.trim() || undefined;

  const ollamaBaseUrl = inferenceProvider === "ollama"
    ? (Bun.env.OLLAMA_BASE_URL?.trim() || "http://127.0.0.1:11434")
    : undefined;

  const extractionStoreThreshold = parseUnitInterval(
    requireEnv("EXTRACTION_STORE_THRESHOLD"),
    "EXTRACTION_STORE_THRESHOLD",
  );

  const extractionDisplayThreshold = parseUnitInterval(
    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
    "EXTRACTION_DISPLAY_THRESHOLD",
  );

  if (extractionDisplayThreshold < extractionStoreThreshold) {
    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
  }

  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
  const extractionModelId = requireEnv("EXTRACTION_MODEL");
  const pmAgentModelId = Bun.env.PM_AGENT_MODEL && Bun.env.PM_AGENT_MODEL.trim().length > 0
    ? Bun.env.PM_AGENT_MODEL.trim()
    : extractionModelId;
  const analyticsAgentModelId = requireEnv("ANALYTICS_MODEL");
  const embeddingModelId = requireEnv("EMBEDDING_MODEL");
  const embeddingDimension = parsePositiveInteger(requireEnv("EMBEDDING_DIMENSION"), "EMBEDDING_DIMENSION");

  const surrealUrl = requireEnv("SURREAL_URL");
  const surrealUsername = requireEnv("SURREAL_USERNAME");
  const surrealPassword = requireEnv("SURREAL_PASSWORD");
  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
  const surrealDatabase = requireEnv("SURREAL_DATABASE");

  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
  const observerModelId = Bun.env.OBSERVER_MODEL && Bun.env.OBSERVER_MODEL.trim().length > 0
    ? Bun.env.OBSERVER_MODEL.trim()
    : extractionModelId;
  const scorerModelId = Bun.env.SCORER_MODEL && Bun.env.SCORER_MODEL.trim().length > 0
    ? Bun.env.SCORER_MODEL.trim()
    : extractionModelId;
  const githubWebhookSecret = Bun.env.GITHUB_WEBHOOK_SECRET?.trim() || undefined;
  const betterAuthSecret = requireEnv("BETTER_AUTH_SECRET");
  const betterAuthUrl = requireEnv("BETTER_AUTH_URL");
  const githubClientId = requireEnv("GITHUB_CLIENT_ID");
  const githubClientSecret = requireEnv("GITHUB_CLIENT_SECRET");

  const openRouterReasoning = inferenceProvider === "openrouter"
    ? parseOpenRouterReasoning()
    : undefined;

  return {
    inferenceProvider,
    ...(openRouterApiKey ? { openRouterApiKey } : {}),
    ...(ollamaBaseUrl ? { ollamaBaseUrl } : {}),
    chatAgentModelId,
    extractionModelId,
    pmAgentModelId,
    analyticsAgentModelId,
    embeddingModelId,
    embeddingDimension,
    extractionStoreThreshold,
    extractionDisplayThreshold,
    ...(openRouterReasoning ? { openRouterReasoning } : {}),
    surrealUrl,
    surrealUsername,
    surrealPassword,
    surrealNamespace,
    surrealDatabase,
    port,
    observerModelId,
    scorerModelId,
    ...(githubWebhookSecret ? { githubWebhookSecret } : {}),
    betterAuthSecret,
    betterAuthUrl,
    githubClientId,
    githubClientSecret,
  };
}

function requireEnv(name: string): string {
  const value = Bun.env[name];
  if (!value || value.trim().length === 0) {
    throw new Error(`${name} is required`);
  }

  return value;
}

function parsePositiveInteger(value: string, envName: string): number {
  const parsed = Number(value);
  if (!Number.isInteger(parsed) || parsed < 1) {
    throw new Error(`${envName} must be a positive integer`);
  }
  return parsed;
}

function parseUnitInterval(value: string, envName: string): number {
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
    throw new Error(`${envName} must be a number between 0 and 1`);
  }

  return parsed;
}

function parseInferenceProvider(): InferenceProvider {
  const value = Bun.env.INFERENCE_PROVIDER?.trim().toLowerCase();
  if (!value || value === "openrouter") return "openrouter";
  if (value === "ollama") return "ollama";
  throw new Error("INFERENCE_PROVIDER must be one of: openrouter, ollama");
}

function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;

  if (!effortValue && !maxTokensValue) {
    return undefined;
  }

  const reasoning: OpenRouterReasoningOptions = {};

  if (effortValue) {
    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];

    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
    }
    reasoning.effort = effortValue as OpenRouterReasoningEffort;
  }

  if (maxTokensValue) {
    const parsed = Number(maxTokensValue);
    if (!Number.isFinite(parsed) || parsed < 1) {
      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
    }
    reasoning.max_tokens = parsed;
  }

  return reasoning;
}

// Orchestrator wiring
const orchestratorHandlers = wireOrchestratorRoutes({
  surreal: deps.surreal,
  shellExec,
  brainBaseUrl: `http://127.0.0.1:${config.port}`,
  sseRegistry: deps.sse,
  queryFn: query,
  auth: deps.auth,
});

return Bun.serve({
  port: config.port,
  idleTimeout: 0,
  routes: {
    "/healthz": {
      GET: withRequestLogging("GET /healthz", "GET", async () => jsonResponse({ status: "ok" }, 200)),
    },
    "/api/workspaces": {
      POST: withRequestLogging("POST /api/workspaces", "POST", (request) => workspaceHandlers.handleCreateWorkspace(request)),
    },
    "/api/workspaces/:workspaceId/bootstrap": {
      GET: withRequestLogging(
        "GET /api/workspaces/:workspaceId/bootstrap",
        "GET",
        (request) => workspaceHandlers.handleWorkspaceBootstrap(request.params.workspaceId),
      ),
    },
    "/api/workspaces/:workspaceId/sidebar": {
      GET: withRequestLogging(
        "GET /api/workspaces/:workspaceId/sidebar",
        "GET",
        (request) => workspaceHandlers.handleWorkspaceSidebar(request.params.workspaceId),
      ),
    },
    "/api/workspaces/:workspaceId/repo-path": {
      POST: withRequestLogging(
        "POST /api/workspaces/:workspaceId/repo-path",
        "POST",
        (request) => workspaceHandlers.handleUpdateRepoPath(request.params.workspaceId, request),
      ),

        ),
      },
      // OAuth 2.1 RAR+DPoP — Bridge session-to-token exchange
      "/api/auth/bridge/exchange": {
        POST: withRequestLogging("POST /api/auth/bridge/exchange", "POST", (request) =>
          bridgeExchangeHandler(request),
        ),
      },
      // AS JWKS endpoint — public keys for token verification
      "/api/auth/brain/.well-known/jwks": {
        GET: withRequestLogging("GET /api/auth/brain/.well-known/jwks", "GET", async () =>
          jsonResponse(buildJwksResponse(deps.asSigningKey), 200),
        ),
      },
      // OAuth 2.1 discovery — proxy root-level .well-known to better-auth handler
      "/.well-known/oauth-authorization-server/*": {
        GET: async (request) => deps.auth.handler(request),
      },
      "/.well-known/oauth-protected-resource": {
        GET: () => jsonResponse({
          resource: config.betterAuthUrl,
          authorization_servers: [config.betterAuthUrl],
          scopes_supported: Object.keys(BRAIN_SCOPES),
          bearer_methods_supported: ["header"],
        }, 200),
      },
      "/api/auth/oauth-client/:clientId": {
        GET: withRequestLogging(
          "GET /api/auth/oauth-client/:clientId",
          "GET",
          createClientInfoHandler(deps.surreal),
        ),
      },
      "/api/auth/*": async (request) => deps.auth.handler(request),
      "/": appHtml,
      "/*": appHtml,
    },
  });
}

function detectTransport(url: string): string {
  if (url.startsWith("wss://")) return "wss";
  if (url.startsWith("ws://")) return "ws";
  if (url.startsWith("https://")) return "https";
  return "http";
}

export async function startServer(): Promise<void> {
  const config = loadServerConfig();
  const runtime = await createRuntimeDependencies(config);
  await ensureDefaultWorkspaceProjectScope(runtime.surreal);

  const deps: ServerDependencies = {
    config,
    surreal: runtime.surreal,
    analyticsSurreal: runtime.analyticsSurreal,
    auth: runtime.auth,
    chatAgentModel: runtime.chatAgentModel,
    extractionModel: runtime.extractionModel,
    pmAgentModel: runtime.pmAgentModel,
    analyticsAgentModel: runtime.analyticsAgentModel,
    embeddingModel: runtime.embeddingModel,
    observerModel: runtime.observerModel,
    scorerModel: runtime.scorerModel,
    sse: createSseRegistry(),
    inflight: createInflightTracker(),
    asSigningKey: runtime.asSigningKey,
    nonceCache: createNonceCache(),
  };

  const server = createBrainServer(deps);

  // Recover intents stuck in pending_veto with expired windows (fire-and-forget)
  const vetoManager = createVetoManager();
  deps.inflight.track(
    vetoManager.recoverExpiredWindows({
      updateStatus: (intentId, status) => updateIntentStatus(deps.surreal, intentId, status),
      emitVetoEvent: (event) => logInfo("intent.veto.recovery", "Recovered expired veto window", { event }),
      queryExpiredVetoIntents: () => queryExpiredVetoIntents(deps.surreal),
    }).catch((err) => {
      logError("intent.veto.recovery", "Failed to recover expired veto windows", err);
    }),
  );

  logInfo("server.started", "Brain app server started", {
    port: server.port,
    host: "127.0.0.1",
    chatAgentModelId: config.chatAgentModelId,
    extractionModelId: config.extractionModelId,
    pmAgentModelId: config.pmAgentModelId,
    embeddingModelId: config.embeddingModelId,
    embeddingDimension: config.embeddingDimension,
    extractionStoreThreshold: config.extractionStoreThreshold,
    extractionDisplayThreshold: config.extractionDisplayThreshold,
    surrealTransport: detectTransport(config.surrealUrl),
    surrealNamespace: config.surrealNamespace,
    surrealDatabase: config.surrealDatabase,
    openRouterReasoningEnabled: config.openRouterReasoning !== undefined,
  });
}

