import { logInfo, logError, elapsedMs } from "../http/observability";
import { jsonError } from "../http/response";

const ANTHROPIC_API_URL = "https://api.anthropic.com";

const FORWARDED_HEADERS = [
  "anthropic-version",
  "anthropic-beta",
  "content-type",
] as const;

export function createAnthropicProxyHandler(): (request: Request) => Promise<Response> {
  const apiKey = Bun.env.ANTHROPIC_API_KEY?.trim();
  if (!apiKey) {
    return async () => jsonError("ANTHROPIC_API_KEY not configured on proxy", 503);
  }

  return (request: Request) => proxyToAnthropic(request, apiKey);
}

async function proxyToAnthropic(request: Request, apiKey: string): Promise<Response> {
  const startedAt = performance.now();
  const url = new URL(request.url);
  const upstreamPath = url.pathname.replace(/^\/anthropic/, "");
  const upstreamUrl = `${ANTHROPIC_API_URL}${upstreamPath}`;

  const headers = new Headers();
  headers.set("x-api-key", apiKey);
  for (const name of FORWARDED_HEADERS) {
    const value = request.headers.get(name);
    if (value) headers.set(name, value);
  }

  const body = await request.text();
  let parsed: { model?: string; stream?: boolean; max_tokens?: number } | undefined;
  try {
    parsed = JSON.parse(body);
  } catch {
    // not JSON — forward as-is
  }

  const isStreaming = parsed?.stream === true;

  logInfo("proxy.anthropic.request", "Forwarding to Anthropic", {
    method: request.method,
    path: upstreamPath,
    model: parsed?.model,
    stream: isStreaming,
    max_tokens: parsed?.max_tokens,
  });

  let upstream: Response;
  try {
    upstream = await fetch(upstreamUrl, {
      method: request.method,
      headers,
      body: request.method !== "GET" ? body : undefined,
    });
  } catch (error) {
    logError("proxy.anthropic.upstream_error", "Failed to reach Anthropic API", error);
    return jsonError("upstream unreachable", 502);
  }

  if (!isStreaming) {
    const responseBody = await upstream.text();
    let responseData: { model?: string; usage?: { input_tokens?: number; output_tokens?: number }; stop_reason?: string } | undefined;
    try {
      responseData = JSON.parse(responseBody);
    } catch {
      // non-JSON response — forward as-is
    }

    logInfo("proxy.anthropic.response", "Anthropic response", {
      status: upstream.status,
      model: responseData?.model,
      input_tokens: responseData?.usage?.input_tokens,
      output_tokens: responseData?.usage?.output_tokens,
      stop_reason: responseData?.stop_reason,
      latency_ms: elapsedMs(startedAt),
    });

    return new Response(responseBody, {
      status: upstream.status,
      headers: {
        "Content-Type": upstream.headers.get("content-type") ?? "application/json",
        "Access-Control-Allow-Origin": "*",
      },
    });
  }

  // Streaming: pipe SSE events through, inspecting for usage data
  const { readable, writable } = new TransformStream<Uint8Array>();
  const writer = writable.getWriter();
  const reader = upstream.body!.getReader();
  const decoder = new TextDecoder();

  const streamContext = {
    model: parsed?.model,
    inputTokens: 0,
    outputTokens: 0,
    stopReason: undefined as string | undefined,
  };

  (async () => {
    try {
      let buffer = "";
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        // Forward raw bytes immediately
        await writer.write(value);

