  9→type SearchEntityRow = {
 10→  id: RecordId<string, string>;
 11→  kind: EntityKind;
 12→  text: string;
 13→  score: number;
 14→};
 15→
 16→// BM25 full-text search queries per entity type.
 17→// Queries run from app layer because:
 18→// 1. search::score() / @N@ don't work inside DEFINE FUNCTION (https://github.com/surrealdb/surrealdb/issues/7013)
 19→// 2. @N@ doesn't work with SDK bound parameters — search term must be a string literal
 20→
 21→function escapeSearchQuery(query: string): string {
 22→  return query.replace(/\\/g, "\\\\").replace(/'/g, "\\'");
 23→}
 24→
 25→function buildWorkspaceSearchSQL(escapedQuery: string): string {
 26→  const q = `'${escapedQuery}'`;
 27→  return `
 28→SELECT id, "task" AS kind, title AS text, search::score(1) AS score
 29→FROM task WHERE title @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 30→
 31→SELECT id, "decision" AS kind, summary AS text, search::score(1) AS score
 32→FROM decision WHERE summary @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 33→
 34→SELECT id, "question" AS kind, text AS text, search::score(1) AS score
 35→FROM question WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 36→
 37→SELECT id, "observation" AS kind, text AS text, search::score(1) AS score
 38→FROM observation WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 39→
 40→SELECT id, "suggestion" AS kind, text AS text, search::score(1) AS score
 41→FROM suggestion WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 42→
 43→SELECT id, "feature" AS kind, name AS text, search::score(1) AS score
 44→FROM feature WHERE name @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 45→
 46→SELECT id, "project" AS kind, name AS text, search::score(1) AS score
 47→FROM project WHERE name @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 48→
 49→SELECT id, "person" AS kind, name AS text, search::score(1) AS score
 50→FROM person WHERE name @1@ ${q} ORDER BY score DESC LIMIT $limit;
 51→
 52→SELECT id, "message" AS kind, text AS text, search::score(1) AS score
 53→FROM message WHERE text @1@ ${q} AND conversation.workspace = $workspace ORDER BY score DESC LIMIT $limit;
 54→`;
 55→}
 56→
 57→function buildProjectSearchSQL(escapedQuery: string): string {
 58→  const q = `'${escapedQuery}'`;
 59→  return `
 60→LET $project_entity_ids = SELECT VALUE in FROM belongs_to WHERE out = $project;
 61→
 62→SELECT id, "task" AS kind, title AS text, search::score(1) AS score
 63→FROM task WHERE title @1@ ${q} AND workspace = $workspace AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;
 64→
 65→SELECT id, "decision" AS kind, summary AS text, search::score(1) AS score
 66→FROM decision WHERE summary @1@ ${q} AND workspace = $workspace AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;
 67→
 68→SELECT id, "question" AS kind, text AS text, search::score(1) AS score
 69→FROM question WHERE text @1@ ${q} AND workspace = $workspace AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;
 70→
 71→SELECT id, "observation" AS kind, text AS text, search::score(1) AS score
 72→FROM observation WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 73→
 74→SELECT id, "suggestion" AS kind, text AS text, search::score(1) AS score
 75→FROM suggestion WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 76→
 77→SELECT id, "feature" AS kind, name AS text, search::score(1) AS score
 78→FROM feature WHERE name @1@ ${q} AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;
 79→
 80→SELECT id, "message" AS kind, text AS text, search::score(1) AS score
 81→FROM message WHERE text @1@ ${q} AND conversation.workspace = $workspace ORDER BY score DESC LIMIT $limit;
 82→`;
 83→}
 84→
 85→export function createEntitySearchHandler(deps: ServerDependencies): (url: URL) => Promise<Response> {
 86→  return (url: URL) => handleEntitySearch(deps, url);
 87→}
 88→
 89→async function handleEntitySearch(deps: ServerDependencies, url: URL): Promise<Response> {
 90→  const startedAt = performance.now();
 91→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 92→  if (!workspaceId) {
 93→    return jsonError("workspaceId is required", 400);
 94→  }
 95→
 96→  const projectId = url.searchParams.get("projectId")?.trim();
 97→
 98→  const query = url.searchParams.get("q")?.trim();
 99→  if (!query) {
100→    return jsonError("q is required", 400);
101→  }
102→
103→  const rawLimit = url.searchParams.get("limit");
104→  const parsedLimit = Number(rawLimit ?? "10");
105→  if (!Number.isFinite(parsedLimit) || parsedLimit < 1) {
106→    return jsonError("limit must be a positive number", 400);
107→  }
108→
109→  const limit = Math.min(Math.floor(parsedLimit), 100);
110→  logDebug("http.request.validated", "Entity search request validated", {
111→    workspaceId,
112→    projectId,
113→    limit,
114→    queryLength: query.length,
115→  });
116→  logInfo("entity.search.started", "Entity search started", {
117→    workspaceId,
118→    projectId,
119→    limit,
120→  });
121→
122→  let workspaceRecord: RecordId<"workspace", string>;
123→  let projectRecord: RecordId<"project", string> | undefined;
124→
125→  try {
126→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
127→    if (projectId) {
128→      projectRecord = await resolveWorkspaceProjectRecord(deps.surreal, workspaceRecord, projectId);
129→    }
130→  } catch (error) {
131→    if (error instanceof HttpError) {
132→      logWarn("entity.search.http_error", "Entity search failed with client-facing error", {
133→        workspaceId,
134→        projectId,
135→        statusCode: error.status,
136→      });
137→      return jsonError(error.message, error.status);
138→    }
139→
140→    logError("entity.search.scope_validation.failed", "Entity search scope validation failed", error, {
141→      workspaceId,
142→      projectId,
143→    });
144→    const errorText = error instanceof Error ? error.message : "failed to validate scope";
145→    return jsonError(errorText, 500);
146→  }
147→
148→  const escaped = escapeSearchQuery(query);
149→  const sql = projectRecord
150→    ? buildProjectSearchSQL(escaped)
151→    : buildWorkspaceSearchSQL(escaped);
152→
153→  const bindings = {
154→    limit,
155→    workspace: workspaceRecord,
156→    ...(projectRecord ? { project: projectRecord } : {}),
157→  };
158→
159→  const results = await deps.surreal.query(sql, bindings);
160→
161→  const allRows = (results as unknown as SearchEntityRow[][])
162→    .filter(Array.isArray)
163→    .flat()
164→    .sort((a, b) => b.score - a.score)
165→    .slice(0, limit);
166→
167→  const responseRows = allRows.map((row) => ({
168→    id: row.id.id as string,
169→    kind: row.kind,
170→    text: row.text,
171→    confidence: row.score,
172→    sourceId: "",
173→    sourceKind: "message",
174→  } satisfies SearchEntityResponse));
175→
176→  logInfo("entity.search.completed", "Entity search completed", {
177→    workspaceId,
178→    projectId,
179→    limit,
180→    resultCount: responseRows.length,
181→    durationMs: elapsedMs(startedAt),
182→  });
183→
184→  return jsonResponse(responseRows, 200);
185→}
186→

 1→export function jsonError(message: string, status: number): Response {
