 3→}
 4→
 5→export function jsonResponse(payload: object, status: number): Response {
 6→  return new Response(JSON.stringify(payload), {
 7→    status,
 8→    headers: {
 9→      "Content-Type": "application/json",
10→      "Access-Control-Allow-Origin": "*",
11→    },
12→  });
