 32→async function handleAcceptWorkItem(
 33→  deps: ServerDependencies,
 34→  workspaceId: string,
 35→  request: Request,
 36→): Promise<Response> {
 37→  let body: unknown;
 38→  try {
 39→    body = await request.json();
