 41→    return jsonError("invalid JSON body", 400);
 42→  }
 43→
 44→  const parsed = acceptWorkItemSchema.safeParse(body);
 45→  if (!parsed.success) {
 46→    return jsonError(`invalid work item: ${parsed.error.message}`, 400);
 47→  }
 48→
 49→  const item = parsed.data;
 50→
 51→  let workspaceRecord: RecordId<"workspace", string>;
 52→  try {
 53→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 54→  } catch (error) {
