  1→import { logInfo, logError, elapsedMs } from "../http/observability";
  2→import { jsonError } from "../http/response";
  3→
  4→const ANTHROPIC_API_URL = "https://api.anthropic.com";
  5→
  6→const FORWARDED_HEADERS = [
  7→  "anthropic-version",
  8→  "anthropic-beta",
  9→  "content-type",
 10→] as const;
 11→
 12→export function createAnthropicProxyHandler(): (request: Request) => Promise<Response> {
 13→  const apiKey = Bun.env.ANTHROPIC_API_KEY?.trim();
 14→  if (!apiKey) {
 15→    return async () => jsonError("ANTHROPIC_API_KEY not configured on proxy", 503);
 16→  }
 17→
 18→  return (request: Request) => proxyToAnthropic(request, apiKey);
 19→}
 20→
 21→async function proxyToAnthropic(request: Request, apiKey: string): Promise<Response> {
 22→  const startedAt = performance.now();
 23→  const url = new URL(request.url);
 24→  const upstreamPath = url.pathname.replace(/^\/proxy\/llm\/anthropic/, "");
 25→  const upstreamUrl = `${ANTHROPIC_API_URL}${upstreamPath}`;
 26→
 27→  const headers = new Headers();
 28→  headers.set("x-api-key", apiKey);
 29→  for (const name of FORWARDED_HEADERS) {
 30→    const value = request.headers.get(name);
 31→    if (value) headers.set(name, value);
 32→  }
 33→
 34→  const body = await request.text();
 35→  let parsed: { model?: string; stream?: boolean; max_tokens?: number } | undefined;
 36→  try {
 37→    parsed = JSON.parse(body);
 38→  } catch {
 39→    // not JSON — forward as-is
 40→  }
 41→
 42→  const isStreaming = parsed?.stream === true;
 43→
 44→  logInfo("proxy.anthropic.request", "Forwarding to Anthropic", {
 45→    method: request.method,
 46→    path: upstreamPath,
 47→    model: parsed?.model,
 48→    stream: isStreaming,
 49→    max_tokens: parsed?.max_tokens,
 50→  });
 51→
 52→  let upstream: Response;
 53→  try {
 54→    upstream = await fetch(upstreamUrl, {
 55→      method: request.method,
 56→      headers,
 57→      body: request.method !== "GET" ? body : undefined,
 58→    });
 59→  } catch (error) {
 60→    logError("proxy.anthropic.upstream_error", "Failed to reach Anthropic API", error);
 61→    return jsonError("upstream unreachable", 502);
 62→  }
 63→
 64→  if (!isStreaming) {
 65→    const responseBody = await upstream.text();
 66→    let responseData: { model?: string; usage?: { input_tokens?: number; output_tokens?: number }; stop_reason?: string } | undefined;
 67→    try {
 68→      responseData = JSON.parse(responseBody);
 69→    } catch {
 70→      // non-JSON response — forward as-is
 71→    }
 72→
 73→    logInfo("proxy.anthropic.response", "Anthropic response", {
 74→      status: upstream.status,
 75→      model: responseData?.model,
 76→      input_tokens: responseData?.usage?.input_tokens,
 77→      output_tokens: responseData?.usage?.output_tokens,
 78→      stop_reason: responseData?.stop_reason,
 79→      latency_ms: elapsedMs(startedAt),
 80→    });
 81→
 82→    return new Response(responseBody, {
 83→      status: upstream.status,
 84→      headers: {
 85→        "Content-Type": upstream.headers.get("content-type") ?? "application/json",
 86→        "Access-Control-Allow-Origin": "*",
 87→      },
 88→    });
 89→  }
 90→
 91→  // Streaming: pipe SSE events through, inspecting for usage data
 92→  const { readable, writable } = new TransformStream<Uint8Array>();
 93→  const writer = writable.getWriter();
 94→  const reader = upstream.body!.getReader();
 95→  const decoder = new TextDecoder();
 96→
 97→  const streamContext = {
 98→    model: parsed?.model,
 99→    inputTokens: 0,
100→    outputTokens: 0,
101→    stopReason: undefined as string | undefined,
102→  };
103→
104→  (async () => {
105→    try {
106→      let buffer = "";
107→      while (true) {
108→        const { done, value } = await reader.read();
109→        if (done) break;
110→
111→        // Forward raw bytes immediately
112→        await writer.write(value);
113→
114→        // Inspect for usage data (non-blocking parse)
115→        buffer += decoder.decode(value, { stream: true });
116→        buffer = extractSSEUsage(buffer, streamContext);
117→      }
118→    } catch (error) {
119→      logError("proxy.anthropic.stream_error", "SSE relay error", error);
120→    } finally {
